1	\chapter{The Abel--Jacobi map}
2	\label{chap:AbelJacobi}
3	
4	Let $C$ be a smooth proper curve over $k$ as in Chapter~\ref{chap:Genus}, and let $\Jac(C)$ be its Jacobian (Definition~\ref{def:Jacobian}). The constructions of this chapter consume only the Albanese universal property of $\Jac(C)$, as packaged by Definition~\ref{def:IsAlbanese} and provided uniformly in the marked point by Theorem~\ref{thm:nonempty_jacobianWitness}. The Lean formalisation closes every block in this chapter by a single projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$; the corresponding classical line-bundle / Pic-scheme description is recorded as a remark for each block.
5	
6	\section{Definition}
7	
8	\begin{definition}\leanok
9	[Abel--Jacobi map]
10	  \label{def:ofCurve}
11	  \lean{AlgebraicGeometry.Jacobian.ofCurve}
12	  \uses{def:Jacobian, def:IsAlbanese, thm:nonempty_jacobianWitness}
13	  Let $P \colon \Spec k \to C$ be a $k$-rational point of $C$, equivalently a morphism $P \colon \mathbf 1 \to C$ in the category of $k$-schemes over $\Spec k$. By Theorem~\ref{thm:nonempty_jacobianWitness} the Jacobian $\Jac(C)$ of Definition~\ref{def:Jacobian} carries, for each such marked point $P$, an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}. The \emph{Abel--Jacobi map at $P$} is the universal pointed morphism $\iota_P$ supplied by that Albanese structure:
14	  \[
15	    \alpha_P \;:=\; \iota_P \;\colon\; C \;\longrightarrow\; \Jac(C).
16	  \]
17	  Equivalently, $\alpha_P$ is the projection of the universal-pointed-morphism field of the Albanese predicate $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, evaluated at the marked point $P$.
18	\end{definition}
19	
20	\begin{remark}
21	[Classical description (Pic-scheme route)]
22	  \label{rem:ofCurve_classical}
23	  \uses{def:ofCurve, thm:nonempty_jacobianWitness}
24	  Classically (cf.\ Hartshorne~III.4 and FGA Explained, Chapter~9), the Abel--Jacobi map at $P$ admits the line-bundle description
25	  \[
26	    \alpha_P \colon C \;\longrightarrow\; \Pic^0_{C/k},\qquad Q \;\longmapsto\; [\mathcal O_C(Q - P)].
27	  \]
28	  Functorially, it is the morphism in the category of $k$-schemes induced by the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$ via the universal property of $\Pic^0_{C/k}$ as the moduli space of degree-$0$ line bundles on $C$. The Lean formalisation does not follow this route: the Pic-scheme representability machinery (Route~A of the proof of Theorem~\ref{thm:nonempty_jacobianWitness}, in particular sub-step~A.2) is not currently available in Mathlib. See Layer~I of Chapter~\ref{chap:Jacobian} for the formalisation route actually taken.
29	\end{remark}
30	
31	\section{Pointed property}
32	
33	\begin{lemma}\leanok
34	[$\alpha_P$ sends $P$ to $0$]
35	  \label{lem:comp_ofCurve}
36	  \lean{AlgebraicGeometry.Jacobian.comp_ofCurve}
37	  \uses{def:ofCurve, def:IsAlbanese}
38	  $P \;\circ\; \alpha_P \;=\; \eta[\Jac(C)]$, where $\eta[\Jac(C)]$ is the identity element of the group scheme $\Jac(C)$.
39	\end{lemma}
40	
41	\begin{proof}
42	  \uses{def:ofCurve, def:IsAlbanese, thm:nonempty_jacobianWitness}
43	  \leanok
44	  The Lean closure is the field projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ supplied by Theorem~\ref{thm:nonempty_jacobianWitness}. By Definition~\ref{def:IsAlbanese}, this predicate carries among its data the assertion $P \circ \iota_P = \eta_{\Jac(C)}$ that the universal pointed morphism sends the marked point to the identity of the target group scheme. Since $\alpha_P := \iota_P$ by Definition~\ref{def:ofCurve}, the claim is precisely the pointed-property field of that Albanese structure.
45	\end{proof}
46	
47	\begin{remark}
48	[Classical description]
49	  \label{rem:comp_ofCurve_classical}
50	  \uses{def:ofCurve, lem:comp_ofCurve, rem:ofCurve_classical}
51	  Under the classical Pic-scheme description of Remark~\ref{rem:ofCurve_classical}, the same equality reads at the level of $k$-points as
52	  \[
53	    \alpha_P(P) \;=\; [\mathcal O_C(P - P)] \;=\; [\mathcal O_C] \;=\; 0 \in \Pic^0_{C/k}(k),
54	  \]
55	  and globally as the statement that restricting the universal line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ along the section $(P, \mathrm{id}) \colon C \to C \times C$ gives the trivial line bundle on $C$, hence the zero point of $\Pic^0_{C/k}$. This classical content is not used in the Lean formalisation.
56	\end{remark}
57	
58	\section{Universal (Albanese) property}
59	
60	\begin{theorem}\leanok
61	[Albanese property of the Jacobian]
62	  \label{thm:exists_unique_ofCurve_comp}
63	  \lean{AlgebraicGeometry.Jacobian.exists_unique_ofCurve_comp}
64	  \uses{def:ofCurve, lem:comp_ofCurve, def:IsAlbanese}
65	  Let $A$ be an abelian variety over $k$ --- i.e.\ a smooth proper geometrically irreducible group scheme over $k$. For every pointed morphism $f \colon C \to A$ with $f \circ P = \eta[A]$, there exists a unique group-scheme morphism $g \colon \Jac(C) \to A$ such that $f = \alpha_P \circ g$.
66	  \[
67	  \begin{array}{ccc}
68	    C & \stackrel{f}{\longrightarrow} & A \\
69	    {\scriptstyle\alpha_P} \downarrow & \nearrow {\scriptstyle\exists ! g} & \\
70	    \Jac(C) & &
71	  \end{array}
72	  \]
73	\end{theorem}
74	
75	\begin{proof}
76	  \uses{def:IsAlbanese, thm:nonempty_jacobianWitness, def:ofCurve, lem:comp_ofCurve}
77	  \leanok
78	  The argument has two stages: the Lean closure (a direct projection from an Albanese witness) and the classical description (a Pic-scheme / rigidity argument that the Lean side does not replay).
79	
80	  \emph{Lean closure.} By Theorem~\ref{thm:nonempty_jacobianWitness}, the Jacobian $\Jac(C)$ is, uniformly in the marked point $P$, the underlying scheme of an Albanese witness for the pointed curve $(C, P)$: it carries an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}, whose universal pointed morphism is the Abel--Jacobi map $\alpha_P$ of Definition~\ref{def:ofCurve} (with $\alpha_P \circ P = \eta_{\Jac(C)}$ being Lemma~\ref{lem:comp_ofCurve}). The universal-property data carried by this Albanese structure is, by Definition~\ref{def:IsAlbanese}, exactly the existence-and-uniqueness assertion of the theorem: for every $f \colon C \to A$ with $f \circ P = \eta_A$, there is a unique $g \colon \Jac(C) \to A$ with $f = \alpha_P \circ g$. The Lean side closes the goal by projecting this universal-property field of the Albanese witness $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, applied to the data $(f, hf)$.
81	
82	  \emph{Classical description.} The classical proof of the same statement proceeds in two parts. In positive genus ($g(C) > 0$), the existence and uniqueness of the factorisation come from the Pic-scheme representability theorem together with the Stein factorisation of the Abel--Jacobi morphism: see Theorem~\ref{thm:nonempty_jacobianWitness}, Route~A (sub-steps A.1--A.4) for the line-bundle / universal-property route via $\Pic^0_{C/k}$, and Route~B (sub-steps B.1--B.3) for the symmetric-power / Stein-factorisation route. In genus $0$, the same statement reduces to the rigidity theorem for $C \to A$ --- the named declaration \cref{thm:rigidity_over_kbar} of \cref{chap:RigidityKbar}. This rigidity result is established \emph{over the algebraic closure $\bar k$}: its signature carries an $\mathrm{IsAlgClosed}\,\bar k$ hypothesis, and it is built out of the shared cotangent-vanishing pile pieces (i)+(ii)+(iii) over the algebraically closed base. The resulting equality of morphisms is then descended back to the original base field $k$ by faithfully-flat descent: because $\Spec \bar k \to \Spec k$ is faithfully flat, two $k$-morphisms that agree after base change to $\bar k$ already agree over $k$ (\texttt{AlgebraicGeometry.Flat.epi\_of\_flat\_of\_surjective}). See Theorem~\ref{thm:nonempty_jacobianWitness}, sub-cases C.1--C.3, in particular the seven-step expansion C.2.a--C.2.g, where sub-step C.2.f (faithfully-flat descent of morphism equality from $\bar k$ back to $k$) is the descent step carrying the algebraically-closed-base rigidity conclusion down to the original base field; a base-change-to-$\bar k$ step (establishing rigidity) followed by this descent step is on the M2 critical path. The protected signature of Theorem~\ref{thm:nonempty_jacobianWitness} does \emph{not} assume $C(k) \neq \emptyset$, so the genus-$0$ argument branches on whether a $k$-rational point exists. When $C(k) \neq \emptyset$, the supplied $P \in C(k)$ feeds the pointing hypothesis of \cref{thm:rigidity_over_kbar} directly --- no $C \cong \mathbb P^1_k$ identification is required, sidestepping the Brauer--Severi obstruction (Brauer--Severi conics over $\mathbb Q$ are the standard counterexample to an unconditional $k$-side identification). When $C(k) = \emptyset$, the $\mathtt{isAlbaneseFor}$ field of the genus-$0$ witness (\cref{def:genusZeroWitness}) is vacuously true at the Lean type level: the universal quantifier $\forall\, (P \colon \mathbf{1} \to C)$ ranges over the empty type. None of this classical content is replayed in the Lean formalisation: it is bundled into the deferred existence hypothesis Theorem~\ref{thm:nonempty_jacobianWitness}, whose proof is the project's single explicit foundational gap.
83	\end{proof}
84	
85	\section{Implementation route via the Albanese framework}
86	
87	The three results above are formalised through the Albanese framework of Chapter~\ref{chap:Jacobian}. In the absence of Mathlib's Pic-scheme machinery, the Jacobian is defined (Layer~I) as the underlying scheme of an Albanese witness uniform in the marked point (Theorem~\ref{thm:nonempty_jacobianWitness}); the universal-property data $(\iota_P,\, \text{factorisation})$ is then carried by the Albanese predicate (Definition~\ref{def:IsAlbanese}) and projects directly into the three results of this chapter (Layer~II): the Abel--Jacobi map $\alpha_P := \iota_P$ of Definition~\ref{def:ofCurve}, its pointed property of Lemma~\ref{lem:comp_ofCurve}, and the universal factorisation of Theorem~\ref{thm:exists_unique_ofCurve_comp}. Existence of a uniform-over-$P$ Albanese object is the single remaining mathematical hypothesis pending the formalisation of either Pic-scheme representability (Route~A), symmetric-power quotients plus Stein factorisation (Route~B), or rigidity for $C \to A$ proved over the algebraic closure $\bar k$ and descended to $k$ (genus-$0$ sub-case, via \cref{thm:rigidity_over_kbar}, whose signature carries an $\mathrm{IsAlgClosed}\,\bar k$ hypothesis; the equality of morphisms obtained over $\bar k$ is brought back to $k$ by faithfully-flat descent of morphism equality, which is precisely sub-step C.2.f of \S~C.2).
88	
89	The classical proof via line bundles --- using the universal property of $\Pic^0_{C/k}$, dual abelian varieties, and (for the genus-$0$ sub-case) rigidity for $C \to A$ proved over the algebraic closure $\bar k$ via \cref{thm:rigidity_over_kbar} and descended to $k$ by faithfully-flat descent of morphism equality (\texttt{AlgebraicGeometry.Flat.epi\_of\_flat\_of\_surjective}) --- gives the same conclusions but requires more Mathlib infrastructure than is presently available, as catalogued in the proof of Theorem~\ref{thm:nonempty_jacobianWitness} and the milestone roadmap of \texttt{STRATEGY.md}. The Albanese-framework route used here is mathematically equivalent and bundles all of the missing infrastructure into that single deferred existence hypothesis.
90

1	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with $k$-module coefficients}
2	\label{chap:Cohomology_MayerVietoris}
3	
4	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in $k$-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers $H^n(X,\mathcal F)$ and $H^{\prime n}(U,\mathcal F)$ live in Chapter~\ref{chap:Cohomology_StructureSheafModuleK} and are imported here.
5	
6	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of $H^1(C,\mathcal O_C)$ in Definition~\ref{def:genus}.
7	
8	\section{Functoriality of cohomology in the open variable}
9	\label{sec:hmodule_prime_cohomologyPresheaf}
10	
11	The cohomology-of-an-open carrier $H^{\prime n}(X,\mathcal F)$ is contravariantly functorial in the open variable $X$. Assembling this functoriality yields a presheaf
12	\[
13	  X \longmapsto H^{\prime n}(X, \mathcal F),
14	\]
15	and, varying $\mathcal F$ as well, a bifunctor from sheaves of $k$-modules to presheaves of abelian groups. The codomain is the category of abelian groups because $\Ext$ is always valued there, regardless of the linear enrichment of the source category; the per-fiber $k$-module structure is inherited from the reducible wrapper on $H^{\prime n}$.
16	
17	\begin{definition}\leanok
18	[Cohomology presheaf functor, $H'$ flavor]
19	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
20	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
21	  \uses{def:Scheme_HModule_prime, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
22	  Let $k$ be a field, $C$ a category equipped with a Grothendieck topology $J$, and assume sheafification and $\Ext$ exist for sheaves of $k$-modules on $J$. For $n \in \mathbb N$, define the cohomology presheaf functor
23	  \[
24	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
25	  \]
26	  by the standard composition of the Yoneda embedding, the free-$k$-module functor, sheafification, and the $n$-th $\Ext$ functor.
27	\end{definition}
28	
29	\begin{proof}
30	  \uses{def:Scheme_HModule_prime}
31	  \leanok
32	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
33	\end{proof}
34	
35	\begin{definition}\leanok
36	[Cohomology presheaf, $H'$ flavor]
37	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
38	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
39	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
40	  In the setting of Definition~\ref{def:Scheme_HModule_prime_cohomologyPresheafFunctor}, let $\mathcal F$ be a sheaf of $k$-modules. For $n \in \mathbb N$, define the cohomology presheaf
41	  \[
42	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
43	  \]
44	  to be the evaluation of the bifunctor at $\mathcal F$.
45	\end{definition}
46	
47	\begin{proof}
48	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
49	  \leanok
50	  Direct evaluation of the bifunctor at $\mathcal F$.
51	\end{proof}
52	
53	\begin{remark}
54	  For every object $X$ of $C$, the underlying type of $\mathcal H^{\prime n}(\mathcal F)(X)$ is definitionally equal to $H^{\prime n}(X, \mathcal F)$. The per-fiber $k$-module structure is therefore inherited through the $H'$ wrapper.
55	\end{remark}
56	
57	\begin{remark}[Lean implementation]
58	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level $H'$ carrier.
59	\end{remark}
60	
61	\section{Mayer--Vietoris long exact sequence}
62	\label{sec:hmodule_prime_mayer_vietoris}
63	
64	A Mayer--Vietoris square for a Grothendieck topology $J$ on a category $C$ is a pullback square
65	% NOTE: rendered as a 2x2 array for KaTeX (leanblueprint web); the PDF
66	% build renders the same data via tikz-cd if the package is available.
67	\[
68	  \begin{array}{ccc}
69	    X_1 & \longrightarrow & X_2 \\
70	    \downarrow & & \downarrow \\
71	    X_3 & \longrightarrow & X_4
72	  \end{array}
73	\]
74	that is a $J$-cover: the pair of morphisms $X_2 \to X_4$ and $X_3 \to X_4$ is a covering family, and $X_1$ is the pullback. For a sheaf $\mathcal F$, the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
75	
76	\subsection{The restriction maps}
77	
78	\begin{definition}\leanok
79	[Sum of two restriction maps]
80	  \label{def:Scheme_HModule_prime_toBiprod}
81	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
82	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
83	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
84	  \[
85	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
86	  \]
87	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.
88	\end{definition}
89	
90	\begin{proof}
91	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
92	  \leanok
93	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
94	\end{proof}
95	
96	\begin{definition}\leanok
97	[Difference of two restriction maps]
98	  \label{def:Scheme_HModule_prime_fromBiprod}
99	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
100	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
101	  In the same setting, define the morphism
102	  \[
103	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
104	  \]
105	  to be the biproduct desc of the restriction map $X_1 \to X_2$ and the additive inverse of the restriction map $X_1 \to X_3$.
106	\end{definition}
107	
108	\begin{proof}
109	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
110	  \leanok
111	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
112	\end{proof}
113	
114	\begin{lemma}\leanok
115	[Composition vanishes]
116	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
117	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
118	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
119	  In the setting above,
120	  \[
121	    \fromBiprod \circ \toBiprod \;=\; 0.
122	  \]
123	\end{lemma}
124	
125	\begin{proof}
126	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
127	  \leanok
128	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation $X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4$. Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
129	\end{proof}
130	
131	\subsection{The short exact sequence of sheaves}
132	
133	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of $k$-modules obtained by sheafifying the Yoneda embedding composed with the free-$k$-module functor.
134	
135	\begin{definition}\leanok
136	[Free-$k$-module functor is left adjoint]
137	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
138	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
139	  Let $k$ be a field. The free-$k$-module functor $\Type \to \ModuleCat\,k$ is a left adjoint.
140	\end{definition}
141	
142	\begin{proof}
143	  \leanok
144	  The adjunction is the standard free-forgetful adjunction for $k$-modules. The declaration packages the existing adjunction into the typeclass-witness form.
145	\end{proof}
146	
147	\begin{lemma}\leanok
148	[Pushout of free sheaves]
149	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
150	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
151	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
152	  Let $S$ be a Mayer--Vietoris square. The image of $S$ under the composite functor
153	  \[
154	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
155	  \]
156	  is a pushout square in the category of sheaves of $k$-modules.
157	\end{lemma}
158	
159	\begin{proof}
160	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
161	  \leanok
162	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-$k$-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
163	\end{proof}
164	
165	\begin{definition}\leanok
166	[Short complex of free sheaves]
167	  \label{def:Scheme_HModule_prime_shortComplex}
168	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
169	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
170	  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of sheaves of $k$-modules
171	  \[
172	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
173	  \]
174	  where $f$ is the biproduct lift of the two maps induced by $X_1 \to X_2$ and $-X_1 \to X_3$, and $g$ is the biproduct desc of the two maps induced by $X_2 \to X_4$ and $X_3 \to X_4$. The composition $g \circ f = 0$ follows from the cokernel-cofork condition of the pushout.
175	\end{definition}
176	
177	\begin{proof}
178	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
179	  \leanok
180	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
181	\end{proof}
182	
183	\begin{definition}\leanok
184	[Free-$k$-module functor preserves monomorphisms]
185	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
186	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
187	  Let $k$ be a field. The free-$k$-module functor preserves monomorphisms.
188	\end{definition}
189	
190	\begin{proof}
191	  \leanok
192	  An injective function between types induces an injective $k$-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of $k$-modules is equivalent to injectivity.
193	\end{proof}
194	
195	\begin{lemma}\leanok
196	[The first map is mono]
197	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
198	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
199	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
200	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the first map $f$ is a monomorphism.
201	\end{lemma}
202	
203	\begin{proof}
204	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
205	  \leanok
206	  The map $f$ followed by the second projection is the free-$k$-module functor applied to the monomorphism $X_1 \to X_3$, which is mono because the free functor preserves monomorphisms. Hence $f$ itself is mono.
207	\end{proof}
208	
209	\begin{lemma}\leanok
210	[The second map is epi]
211	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
212	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
213	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
214	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the second map $g$ is an epimorphism.
215	\end{lemma}
216	
217	\begin{proof}
218	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
219	  \leanok
220	  By the pushout lemma, $g$ is the cokernel of $f$, and every cokernel is epi.
221	\end{proof}
222	
223	\begin{lemma}\leanok
224	[Exactness at the middle term]
225	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
226	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
227	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
228	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, exactness holds at the middle term: the image of $f$ equals the kernel of $g$.
229	\end{lemma}
230	
