351	\section{Affine cohomology vanishing carrier predicate}
352	\label{sec:IsAffineHModuleVanishing_iter040}
353	
354	To use a Mayer--Vietoris argument on a 2-affine cover, one needs the positive-degree cohomology of each affine piece to vanish. This is Serre's classical theorem on affine schemes. Since a full scheme-level proof is not yet available in the library, we package the vanishing statement as a hypothesis class.
355	
356	\begin{definition}\leanok
357	[Affine cohomology vanishing carrier predicate]
358	  \label{thm:Scheme_IsAffineHModuleVanishing}
359	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleVanishing}
360	  \uses{def:Scheme_HModule_prime}
361	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules on $C$. The class of affine cohomology vanishing for $F$ asserts that for every affine open $U$ of $C$ and every degree $i > 0$, the open-evaluation cohomology $H^{\prime i}(U, F)$ is a subsingleton (equivalently, the zero $k$-module).
362	\end{definition}
363	
364	\begin{theorem}\leanok
365	[Finite-dimensionality from affine vanishing]
366	  \label{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}
367	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_isAffineHModuleVanishing}
368	  \uses{thm:Scheme_IsAffineHModuleVanishing}
369	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules. Assume affine cohomology vanishing holds for $F$. For any affine open $U$ of $C$ and any $i > 0$, the cohomology group $H^{\prime i}(U, F)$ is finite-dimensional over $k$.
370	\end{theorem}
371	
372	\begin{proof}
373	  \uses{thm:Scheme_IsAffineHModuleVanishing}
374	  \leanok
375	  A subsingleton $k$-module is generated by the empty set, hence finitely generated and finitely presented, hence finite-dimensional.
376	\end{proof}
