378	\section{$H^0$ Hom-finiteness carrier predicate}
379	\label{sec:IsAffineHModuleHomFinite_iter041}
380	
381	Parallel to the affine vanishing class, we package the $H^0$ side as a class-style predicate: on each affine open, the Hom group (morally, the sections) is finite-dimensional over $k$.
382	
383	\begin{definition}\leanok
384	[$H^0$ Hom-finiteness carrier predicate]
385	  \label{thm:Scheme_IsAffineHModuleHomFinite}
386	  \lean{AlgebraicGeometry.Scheme.IsAffineHModuleHomFinite}
387	  \uses{def:Scheme_HModule_prime}
388	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules on $C$. The class of $H^0$ Hom-finiteness for $F$ asserts that for every affine open $U$ of $C$, the morphism group from the sheafified representable at $U$ to $F$ is finite-dimensional over $k$.
389	\end{definition}
390	
391	\begin{theorem}\leanok
392	[Finite-dimensionality of open $H^0$ from Hom-finiteness]
393	  \label{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
394	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_zero_of_isAffineHModuleHomFinite}
395	  \uses{thm:Scheme_IsAffineHModuleHomFinite, thm:Scheme_module_finite_HModule_prime_zero}
396	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules. Assume $H^0$ Hom-finiteness holds for $F$. For any affine open $U$ of $C$, the cohomology group $H^{\prime 0}(U, F)$ is finite-dimensional over $k$.
397	\end{theorem}
