405	\section{Combined affine-corner finite-dimensionality consumer}
406	\label{sec:module_finite_HModule_prime_of_affine_iter042}
407	
408	The two consumers above each cover one degree side: the $H^0$ consumer requires $i = 0$, the positive-degree consumer requires $i > 0$. We fold both into a single uniform statement covering all $i \ge 0$.
409	
410	\begin{theorem}\leanok
411	[Combined affine-corner finite-dimensionality]
412	  \label{thm:Scheme_module_finite_HModule_prime_of_affine}
413	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine}
