416	\end{theorem}
417	
418	\begin{proof}
419	  \uses{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing, thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
420	  \leanok
421	  Case-split on whether $i = 0$ or $i > 0$, delegating to the respective consumer.
422	\end{proof}
