432	\section{Wholespace $H^0$ Hom-finiteness carrier}
433	\label{sec:IsHModuleHomFinite_iter043}
434	
435	The affine-quantified $H^0$ Hom-finiteness class of Section~\ref{sec:IsAffineHModuleHomFinite_iter041} over-quantifies: on a non-trivial proper curve, sections over a proper affine open are typically infinite-dimensional over $k$ (e.g. $k[t]$ on $\mathbb A^1_k$). We introduce a corrective carrier that captures only the \emph{global} Hom group.
436	
437	\begin{definition}\leanok
438	[Wholespace $H^0$ Hom-finiteness carrier predicate]
439	  \label{thm:Scheme_IsHModuleHomFinite}
440	  \lean{AlgebraicGeometry.Scheme.IsHModuleHomFinite}
441	  \uses{def:Scheme_HModule}
442	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules on $C$. The class of wholespace $H^0$ Hom-finiteness asserts that the global morphism group $\Hom(\text{constant sheaf at }k, F)$ is finite-dimensional over $k$.
443	\end{definition}
444	
445	\begin{theorem}\leanok
446	[Finite-dimensionality of global $H^0$ from wholespace Hom-finiteness]
447	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite}
448	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite}
449	  \uses{thm:Scheme_IsHModuleHomFinite, thm:Scheme_module_finite_HModule_zero}
450	  Let $k$ be a field, $C$ a scheme over $\Spec k$, and $F$ a sheaf of $k$-modules. Assume wholespace $H^0$ Hom-finiteness holds for $F$. Then $H^0_{\Module}(F)$ is finite-dimensional over $k$.
451	\end{theorem}
452	
453	\begin{theorem}\leanok
454	[Curve specialisation]
455	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite_curve}
456	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite_curve}
457	  \uses{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite, def:Scheme_toModuleKSheaf}
