465	\section{Stein finiteness of global sections}
466	\label{sec:module_finite_globalSections_iter044}
467	
468	The geometric input for the wholespace Hom-finiteness carrier is Stein's theorem: on a proper integral scheme over a field, global sections are finite-dimensional.
469	
470	\begin{theorem}\leanok
471	[Stein finiteness of global sections]
472	  \label{thm:Scheme_module_finite_globalSections_of_isProper}
473	  \lean{AlgebraicGeometry.Scheme.module_finite_globalSections_of_isProper}
474	  \uses{def:Scheme_kToSection, def:Scheme_algebraSection, def:Scheme_toModuleKSheaf}
475	  Let $k$ be a field and $C$ an integral scheme over $\Spec k$ with proper structure morphism. Then $\Gamma(C, \mathcal O_C)$ is finite-dimensional over $k$.
476	\end{theorem}
477	
478	\begin{proof}
479	  \uses{def:Scheme_kToSection, def:Scheme_algebraSection}
480	  \leanok
481	  Apply the theorem that for an integral scheme with a universally closed, locally finite-type morphism to $\Spec k$, the structure-morphism ring map on global sections is module-finite. Transfer the base ring from $\Gamma(\Spec k, \top)$ to $k$ along the canonical ring isomorphism.
482	\end{proof}
