484	\section{Global-sections evaluation isomorphism}
485	\label{sec:gammaObj_linearEquiv_top}
486	
487	To bridge from global sections (a concrete $k$-module) to the abstract Hom-from-constant-sheaf form, we lift the natural isomorphism between global sections and evaluation at the terminal object to a $k$-linear equivalence.
488	
489	\begin{theorem}\leanok
490	[Global-sections-to-top linear equivalence]
491	  \label{thm:Scheme_SheafGammaObj_linearEquiv_top}
492	  \lean{AlgebraicGeometry.Scheme.SheafGammaObj_linearEquiv_top}
493	  \uses{def:Scheme_toModuleKSheaf}
494	  Let $k$ be a field, $X$ a topological space, and $F$ a sheaf of $k$-modules on $X$. Then there is a $k$-linear equivalence between the global-sections object of $F$ and the evaluation of $F$ at the top open $\top$.
495	\end{theorem}
496	
497	\begin{theorem}\leanok
498	[Finite-dimensionality on global-sections object]
499	  \label{thm:Scheme_module_finite_gammaObj_of_isProper}
500	  \lean{AlgebraicGeometry.Scheme.module_finite_gammaObj_of_isProper}
501	  \uses{thm:Scheme_module_finite_globalSections_of_isProper, thm:Scheme_SheafGammaObj_linearEquiv_top, def:Scheme_toModuleKSheaf}
502	  Let $k$ be a field and $C$ an integral scheme over $\Spec k$ with proper structure morphism. Then the global-sections object of the $k$-module-valued structure sheaf is finite-dimensional over $k$.
503	\end{theorem}
504	
505	\begin{proof}
506	  \uses{thm:Scheme_module_finite_globalSections_of_isProper, thm:Scheme_SheafGammaObj_linearEquiv_top}
507	  \leanok
508	  Combine Theorem~\ref{thm:Scheme_module_finite_globalSections_of_isProper} with the linear equivalence of Theorem~\ref{thm:Scheme_SheafGammaObj_linearEquiv_top}, transporting finite-dimensionality across the symmetric form.
509	\end{proof}
