511	\section{Producer instance for wholespace Hom-finiteness}
512	\label{sec:IsHModuleHomFinite_producer}
513	
514	We now assemble the chain: constant-sheaf/global-sections adjunction, Hom-from-$k$ evaluation, and Stein finiteness, to produce the wholespace $H^0$ Hom-finiteness instance.
515	
516	\begin{lemma}\leanok
517	[Linear lifting of adjoint functors]
518	  \label{lemma:Adjunction_left_adjoint_linear}
519	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
520	  Let $F \dashv G$ be an adjunction between $R$-linear preadditive categories. If $G$ is $R$-linear, then $F$ is $R$-linear.
521	\end{lemma}
522	
523	\begin{lemma}\leanok
524	[Right-adjoint version]
525	  \label{lemma:Adjunction_right_adjoint_linear}
526	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
527	  Dual of Lemma~\ref{lemma:Adjunction_left_adjoint_linear}: if $F$ is $R$-linear, then $G$ is $R$-linear.
528	\end{lemma}
529	
530	\begin{theorem}\leanok
531	[Linear hom-equivalence from an adjunction]
532	  \label{def:Adjunction_homLinearEquiv}
533	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
534	  \uses{lemma:Adjunction_left_adjoint_linear}
535	  Let $F \dashv G$ be an adjunction between $R$-linear preadditive categories with $G$ additive and $R$-linear. Then for all objects $X$ and $Y$, the additive equivalence of the adjunction upgrades to an $R$-linear equivalence between $\Hom(FX, Y)$ and $\Hom(X, GY)$.
536	\end{theorem}
537	
538	\begin{theorem}\leanok
539	[Constant-sheaf / global-sections linear equivalence]
540	  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
541	  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
542	  \uses{def:Adjunction_homLinearEquiv}
543	  Let $k$ be a field, $C$ a Grothendieck site admitting sheafification of $k$-modules, and $F$ a sheaf of $k$-modules. For any $k$-module $X$, there is a $k$-linear equivalence between morphisms from the constant sheaf at $X$ to $F$, and $k$-linear maps from $X$ to the global sections of $F$.
544	\end{theorem}
545	
546	\begin{theorem}\leanok
547	[Hom-from-$k$ evaluation]
548	  \label{def:Scheme_homFromOne_linearEquiv}
549	  \lean{AlgebraicGeometry.Scheme.homFromOne_linearEquiv}
550	  For any field $k$ and $k$-module $M$, there is a canonical $k$-linear equivalence between $\Hom_k(k, M)$ and $M$ given by evaluation at $1$.
551	\end{theorem}
552	
553	\begin{theorem}\leanok
554	[Producer instance for wholespace Hom-finiteness]
555	  \label{inst:Scheme_instIsHModuleHomFinite_toModuleKSheaf}
556	  \lean{AlgebraicGeometry.Scheme.instIsHModuleHomFinite_toModuleKSheaf}
557	  \uses{def:Scheme_constantSheafGammaHom_linearEquiv, def:Scheme_homFromOne_linearEquiv, thm:Scheme_module_finite_gammaObj_of_isProper}
558	  Let $k$ be a field and $C$ an integral scheme over $\Spec k$ with proper structure morphism. Then wholespace $H^0$ Hom-finiteness holds for the $k$-module-valued structure sheaf of $C$.
559	\end{theorem}
560	
561	\begin{proof}
562	  \uses{def:Scheme_constantSheafGammaHom_linearEquiv, def:Scheme_homFromOne_linearEquiv, thm:Scheme_module_finite_gammaObj_of_isProper}
563	  \leanok
564	  Compose the constant-sheaf/global-sections linear equivalence (specialised to $X = k$) with the Hom-from-$k$ evaluation to obtain a linear equivalence between the global Hom group and the global-sections object. Theorem~\ref{thm:Scheme_module_finite_gammaObj_of_isProper} provides finite-dimensionality on the latter; transport across the symmetric form of the equivalence.
565	\end{proof}
566	
567	\begin{remark}
568	  Once this producer instance is registered, the consumer of Theorem~\ref{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite_curve} fires automatically, closing $H^0_{\Module}(\mathcal O_C)$ finite-dimensionality for proper integral curves.
569	\end{remark}
