571	\section{Foundational parameterised \v{C}ech infrastructure}
572	\label{sec:moduleK_cech_parameterised}
573	
574	We generalise the \v{C}ech carriers from the structure sheaf to an arbitrary sheaf of $k$-modules, laying the scaffolding for the \v{C}ech-vs-derived comparison theorem.
575	
576	\begin{definition}\leanok
577	[Parameterised \v{C}ech complex]
578	  \label{def:Scheme_cechCochain}
579	  \lean{AlgebraicGeometry.Scheme.cechCochain}
580	  \uses{def:Scheme_cechCochain_OC}
581	  Let $C$ be a scheme over $\Spec k$, $F$ a sheaf of $k$-modules on $C$, and $\mathcal U$ an indexed family of opens. Define the \v{C}ech cochain complex of $F$ with respect to $\mathcal U$ to be the standard \v{C}ech complex applied to the underlying presheaf of $F$. This is a cochain complex valued in $k$-modules.
582	\end{definition}
583	
584	\begin{definition}\leanok
585	[Parameterised \v{C}ech cohomology]
586	  \label{def:Scheme_cechCohomology}
587	  \lean{AlgebraicGeometry.Scheme.cechCohomology}
588	  \uses{def:Scheme_cechCochain}
589	  With $(C, F, \mathcal U)$ as in Definition~\ref{def:Scheme_cechCochain}, define the $n$-th \v{C}ech cohomology to be the $n$-th homology of the \v{C}ech cochain complex.
590	\end{definition}
591	
592	\begin{theorem}\leanok
593	[\v{C}ech complex bridge to structure-sheaf specialisation]
594	  \label{thm:Scheme_cechCochain_OC_eq}
595	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC_eq}
596	  \uses{def:Scheme_cechCochain, def:Scheme_cechCochain_OC}
597	  The structure-sheaf \v{C}ech complex equals the parameterised \v{C}ech complex at $F = \mathcal O_C$.
598	\end{theorem}
599	
600	\begin{theorem}\leanok
601	[\v{C}ech cohomology bridge to structure-sheaf specialisation]
602	  \label{thm:Scheme_cechCohomology_OC_eq}
603	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC_eq}
604	  \uses{def:Scheme_cechCohomology, def:Scheme_cechCohomology_OC}
605	  The structure-sheaf \v{C}ech cohomology equals the parameterised \v{C}ech cohomology at $F = \mathcal O_C$.
606	\end{theorem}
607	
608	\begin{remark}
609	  These generalisations do not construct any comparison map between \v{C}ech and derived cohomology, nor do they prove vanishing. The substantive work is queued for subsequent iterations.
610	\end{remark}
