631	\end{theorem}
632	
633	\begin{proof}
634	  \uses{def:Scheme_IsCechAcyclicCover}
635	  \leanok
636	  Transport the subsingleton structure along the symmetric form of the comparison isomorphism.
637	\end{proof}
638	
639	\begin{theorem}\leanok
640	[Curve specialisation]
641	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover_curve}
642	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover_curve}
643	  \uses{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover, def:Scheme_toModuleKSheaf}
644	  Curve specialisation of Theorem~\ref{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover} at $F = \mathcal O_C$.
645	\end{theorem}
